const { chromium } = require\('playwright'\);
\(async \(\) => {
  const browser = await chromium.launch\({ headless: true }\);
  const context = await browser.newContext\(\);
  const page = await context.newPage\(\);

  const apiCalls = [];
  page.on\('response', async \(response\) => {
    const url = response.url\(\);
    const ct = response.headers\(\)['content-type'] || '';
    if \(ct.includes\('application/json'\) && url.includes\('pokemon-zone'\)\) {
      try {
        const json = await response.json\(\);
        apiCalls.push\({ url, json }\);
      } catch {}
    }
  }\);

  await page.goto\('https://www.pokemon-zone.com/champions/charizard/', { waitUntil: 'networkidle' }\);
  await page.waitForTimeout\(3000\);

  console.log\('API calls found:', JSON.stringify\(apiCalls, null, 2\)\);
  console.log\('Total:', apiCalls.length\);

  await browser.close\(\);
}\)\(\);
